import torch
import torch.nn as nn
from torch.autograd import Function

# ❌ ANTI-PATTERN: Forgetting context management, leaking memory
class BatsmanScorer(nn.Module):
    def forward(self, innings_data):
        loss_history = []  # PROBLEM: accumulates gradients
        for batch in innings_data:
            output = torch.randn(1000, 1000)  # temporary tensors tracked
            loss = (output ** 2).sum()
            loss_history.append(loss)  # keeps computational graph alive
        return sum(loss_history)

# ✅ BEST PRACTICE: Proper context and gradient checkpointing
class BatsmanScorer(nn.Module):
    def __init__(self):
        super().__init__()
        self.scoring_layer = nn.Linear(100, 50)

    def forward(self, innings_data):
        total_runs = 0
        with torch.no_grad():  # evaluation phase
            for batch in innings_data:
                # Process without tracking gradients
                runs = self.scoring_layer(batch)
                total_runs += runs.sum().item()  # detach and convert to Python
        return total_runs

# ✅ BEST PRACTICE: Custom Function with explicit memory management
class BowlingDelivery(Function):
    @staticmethod
    def forward(ctx, ball_speed, pitch_type, batsman_stance):
        # Store only essential info for backward
        ctx.save_for_backward(ball_speed, batsman_stance)
        ctx.pitch_type = pitch_type  # scalar metadata

        # Compute wicket probability
        wicket_prob = (ball_speed * 0.5 + pitch_type).sigmoid()
        return wicket_prob

    @staticmethod
    def backward(ctx, grad_output):
        ball_speed, batsman_stance = ctx.saved_tensors
        pitch_type = ctx.pitch_type

        # Recompute only what's needed
        grad_ball = grad_output * 0.5 * (1 - ball_speed.sigmoid() ** 2)
        grad_batsman = grad_output * batsman_stance * 0.1
        return grad_ball, None, grad_batsman

# ✅ BEST PRACTICE: Hybrid—Function in Module with checkpointing
class CricketMatchSimulator(nn.Module):
    def __init__(self):
        super().__init__()
        self.bowling = nn.Linear(50, 30)
        self.batting = nn.Linear(30, 20)

    def forward(self, match_state, use_checkpoint=True):
        def run_innings(state):
            with torch.no_grad():
                # Scoring happens without gradient tracking
                runs = self.bowling(state)
                return self.batting(runs)

        if use_checkpoint and self.training:
            # Trade compute for memory—essential for large models
            output = torch.utils.checkpoint.checkpoint(run_innings, match_state)
        else:
            output = run_innings(match_state)
        return output
